export default function App() {
  const [product, setProduct] = useState("BPN");
  const [search, setSearch] = useState("");
  const [filterStatus, setFilterStatus] = useState("ALL");
  const [filterFlag, setFilterFlag] = useState("ALL");
  const [filterRegion, setFilterRegion] = useState("ALL");
  const [expanded, setExpanded] = useState(null);
  const [sortBy, setSortBy] = useState("name");
  const [refreshStatus, setRefreshStatus] = useState(null);
  const [refreshLog, setRefreshLog] = useState([]);
  const [pushStatus, setPushStatus] = useState(null);
  const [lastUpdated, setLastUpdated] = useState("March 2026 (baseline)");
  const [dataStore, setDataStore] = useState({ BPN: BPN_DATA, TRAILS: TRAILS_DATA });

  const data = dataStore[product];
  const switchProduct = (p) => { setProduct(p); setExpanded(null); setFilterStatus("ALL"); setFilterFlag("ALL"); setFilterRegion("ALL"); setSearch(""); };
  const regions = useMemo(() => ["ALL", ...Array.from(new Set(data.map(c => c.region))).sort()], [data]);

  const filtered = useMemo(() => data.filter(c => {
    const s = search.toLowerCase();
    const matchSearch = c.name.toLowerCase().includes(s) || c.region.toLowerCase().includes(s);
    const matchStatus = filterStatus === "ALL" || c.status === filterStatus;
    const matchRegion = filterRegion === "ALL" || c.region === filterRegion;
    const matchFlag =
      filterFlag === "ALL" ||
      (filterFlag === "FATF_BLACK" && c.fatfBlack) ||
      (filterFlag === "FATF_GREY" && c.fatfGrey) ||
      (filterFlag === "CRYPTO_BAN" && c.cryptoBan) ||
      (filterFlag === "COMP" && c.comp) ||
      (filterFlag === "SANCTIONS" && c.bodies.length > 0);
    return matchSearch && matchStatus && matchRegion && matchFlag;
  }).sort((a, b) => {
    if (sortBy === "name") return a.name.localeCompare(b.name);
    if (sortBy === "region") return a.region.localeCompare(b.region) || a.name.localeCompare(b.name);
    if (sortBy === "status") { const order = { [P]:0, [E]:1, [D]:2, [A]:3 }; return (order[a.status]??4) - (order[b.status]??4) || a.name.localeCompare(b.name); }
    return 0;
  }), [data, search, filterStatus, filterFlag, filterRegion, sortBy]);

  const stats = useMemo(() => ({
    total: data.length,
    allowed: data.filter(c => c.status === A).length,
    prohibited: data.filter(c => c.status === P).length,
    edd: data.filter(c => c.status === E).length,
    discretionary: data.filter(c => c.status === D).length,
    fatfBlack: data.filter(c => c.fatfBlack).length,
    fatfGrey: data.filter(c => c.fatfGrey).length,
    crypto: data.filter(c => c.cryptoBan).length,
  }), [data]);

  const handleRefresh = useCallback(async () => {
    setRefreshStatus('loading'); setRefreshLog([]);
    try {
      const prompt = `You are a compliance analyst. BPN/Trails Country Risk Screener baseline March 2026:
FATF BLACKLIST: Iran, Myanmar, North Korea
FATF GREYLIST: Algeria, Angola, Bolivia, Bulgaria, Cameroon, Cote d'Ivoire, DR Congo, Haiti, Kenya, Kuwait, Lao PDR, Lebanon, Monaco, Namibia, Nepal, Papua New Guinea, South Sudan, Syria, Ukraine, Venezuela, Vietnam, Virgin Islands (UK), Yemen
Identify changes since March 2026 to: (1) FATF black/grey lists, (2) new comprehensive sanctions by OFAC/EU/UN/UK/Canada, (3) new complete national crypto bans.
Respond ONLY with JSON (no markdown):
{"asOf":"Month YYYY","fatfBlacklistChanges":[{"country":"Name","change":"added"|"removed","notes":"reason"}],"fatfGreylistChanges":[{"country":"Name","change":"added"|"removed","notes":"reason"}],"newComprehensiveSanctions":[{"country":"Name","bodies":["OFAC"],"notes":"reason"}],"newCryptoBans":[{"country":"Name","notes":"reason"}],"noChangesDetected":true|false}`;
      const response = await fetch("https://api.anthropic.com/v1/messages", {
        method:"POST", headers:{"Content-Type":"application/json"},
        body: JSON.stringify({ model:"claude-sonnet-4-20250514", max_tokens:1000, tools:[{type:"web_search_20250305",name:"web_search"}], messages:[{role:"user",content:prompt}] })
      });
      const result = await response.json();
      const textBlock = result.content?.find(b => b.type === "text");
      if (!textBlock) throw new Error("No text response");
      const parsed = JSON.parse(textBlock.text.replace(/```json|```/g,"").trim());
      const today = new Date().toLocaleDateString("en-GB",{day:"numeric",month:"long",year:"numeric"});
      setLastUpdated(`AI-checked ${today} (data as of ${parsed.asOf||"unknown"})`);
      const log = [];
      const applyChanges = (base) => {
        let updated = [...base];
        if (parsed.noChangesDetected) { log.push({type:"info",msg:"No changes detected since March 2026 baseline."}); return updated; }
        for (const chg of (parsed.fatfBlacklistChanges||[])) { const idx = updated.findIndex(c=>c.name.toLowerCase()===chg.country.toLowerCase()); if (idx>=0) { updated[idx]={...updated[idx],fatfBlack:chg.change==="added"}; if(chg.change==="added"&&updated[idx].status===A) updated[idx]={...updated[idx],status:P,notes:`[AUTO-UPDATED] FATF Blacklisted. ${chg.notes}`}; log.push({type:"warn",msg:`FATF Blacklist: ${chg.country} ${chg.change}. ${chg.notes}`}); } }
        for (const chg of (parsed.fatfGreylistChanges||[])) { const idx = updated.findIndex(c=>c.name.toLowerCase()===chg.country.toLowerCase()); if (idx>=0) { updated[idx]={...updated[idx],fatfGrey:chg.change==="added"}; if(chg.change==="added"&&updated[idx].status===A) updated[idx]={...updated[idx],status:A,notes:`[AUTO-UPDATED] Added to FATF grey list. ${chg.notes} EDD required.`}; log.push({type:chg.change==="added"?"warn":"ok",msg:`FATF Greylist: ${chg.country} ${chg.change}. ${chg.notes}`}); } }
        for (const s of (parsed.newComprehensiveSanctions||[])) { const idx = updated.findIndex(c=>c.name.toLowerCase()===s.country.toLowerCase()); if (idx>=0) { updated[idx]={...updated[idx],bodies:[...new Set([...updated[idx].bodies,...s.bodies])],comp:true,status:P,notes:`[AUTO-UPDATED] New comprehensive sanctions: ${s.bodies.join(", ")}. ${s.notes}`}; log.push({type:"warn",msg:`New sanctions on ${s.country}: ${s.bodies.join(", ")}. ${s.notes}`}); } }
        for (const ban of (parsed.newCryptoBans||[])) { const idx = updated.findIndex(c=>c.name.toLowerCase()===ban.country.toLowerCase()); if (idx>=0) { updated[idx]={...updated[idx],cryptoBan:true,status:P,notes:`[AUTO-UPDATED] New crypto ban. ${ban.notes} Business prohibited.`}; log.push({type:"warn",msg:`New crypto ban: ${ban.country}. ${ban.notes}`}); } }
        if (!parsed.noChangesDetected && log.length===0) log.push({type:"info",msg:"Changes returned but none matched known countries. Review manually."});
        return updated;
      };
      setDataStore({ BPN: applyChanges(dataStore.BPN), TRAILS: applyChanges(dataStore.TRAILS) });
      setRefreshLog(log); setRefreshStatus('done');
    } catch(err) { setRefreshLog([{type:"error",msg:`Refresh failed: ${err.message}`}]); setRefreshStatus('error'); }
  }, [dataStore]);

  const handlePushToClickUp = useCallback(async () => {
    setPushStatus('loading');
    try {
      const prohibited = data.filter(c=>c.status===P).sort((a,b)=>a.name.localeCompare(b.name));
      const edd = data.filter(c=>c.status===E).sort((a,b)=>a.name.localeCompare(b.name));
      const disc = data.filter(c=>c.status===D).sort((a,b)=>a.name.localeCompare(b.name));
      const today = new Date().toLocaleDateString("en-GB",{day:"numeric",month:"long",year:"numeric"});
      const md = `# ${product} Country Risk Screener\n**Last updated:** ${today} | ${lastUpdated}\n**Product:** ${product} | **Total:** ${data.length} | **Prohibited:** ${prohibited.length} | **EDD:** ${edd.length}${disc.length>0?` | **Discretionary:** ${disc.length}`:""} | **Allowed:** ${data.filter(c=>c.status===A).length}\n\n---\n\n## 🔴 Prohibited (${prohibited.length})\n\n${prohibited.map(c=>{const f=[c.fatfBlack&&"FATF Black",c.fatfGrey&&"FATF Grey",c.cryptoBan&&"Crypto Ban",c.comp&&"Comp. Sanctions"].filter(Boolean).join(", ")||"None";return`### ${c.name} (${c.region})\n**Flags:** ${f} | **Bodies:** ${c.bodies.join(", ")||"None"}\n\n${c.notes}\n`;}).join("\n")}${edd.length>0?`\n---\n\n## 🟡 High Risk — EDD Required (${edd.length})\n\n${edd.map(c=>{const f=[c.fatfBlack&&"FATF Black",c.fatfGrey&&"FATF Grey",c.cryptoBan&&"Crypto Ban",c.comp&&"Comp. Sanctions"].filter(Boolean).join(", ")||"None";return`### ${c.name} (${c.region})\n**Flags:** ${f} | **Bodies:** ${c.bodies.join(", ")||"None"}\n\n${c.notes}\n`;}).join("\n")}`:""}${disc.length>0?`\n---\n\n## 🟠 Discretionary — Leadership Decision Required (${disc.length})\n\n${disc.map(c=>`### ${c.name} (${c.region})\n\n${c.notes}\n`).join("\n")}`:""}`;
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method:"POST", headers:{"Content-Type":"application/json"},
        body: JSON.stringify({ model:"claude-sonnet-4-20250514", max_tokens:1000, mcp_servers:[{type:"url",url:"https://mcp.clickup.com/mcp",name:"clickup"}], messages:[{role:"user",content:`Create a new page in ClickUp document ID "2ky41vw1-71173", as a sub-page of parent page ID "2ky41vw1-61013". Name it "${product} Country Risk Screener — ${today}". Use content_format text/md with this content:\n\n${md}`}] })
      });
      await res.json(); setPushStatus('done');
    } catch(err) { setPushStatus('error'); }
  }, [data, product, lastUpdated]);

  const Spinner = () => <svg className="w-4 h-4 animate-spin" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"/><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"/></svg>;

  return (
    <div className="min-h-screen bg-gray-50 font-sans">
      <div className="bg-white border-b border-gray-200 px-6 py-4">
        <div className="max-w-6xl mx-auto">
          <div className="flex items-start justify-between flex-wrap gap-3">
            <div>
              <div className="flex items-center gap-3 mb-1">
                <div className="bg-white rounded px-2 py-1"><img src="data:image/png;base64," alt="Polygon" className="h-8" style={{mixBlendMode:"multiply"}} /></div>
                <h1 className="text-xl font-semibold text-gray-900">Country Risk Screener</h1>
              </div>
              <p className="text-sm text-gray-500 ml-11">FATF · Crypto Bans · Sanctions · {stats.total} jurisdictions</p>
              <p className="text-xs text-gray-400 ml-11 mt-0.5">Last updated: {lastUpdated}</p>
            </div>
            <div className="flex gap-2 flex-wrap items-center">
              <button onClick={handleRefresh} disabled={refreshStatus==='loading'} className={`flex items-center gap-2 px-3 py-2 rounded-lg text-sm font-medium border transition-colors ${refreshStatus==='loading'?'bg-gray-100 text-gray-400 border-gray-200 cursor-not-allowed':refreshStatus==='done'?'bg-green-50 text-green-700 border-green-200 hover:bg-green-100':refreshStatus==='error'?'bg-red-50 text-red-700 border-red-200':'bg-blue-50 text-blue-700 border-blue-200 hover:bg-blue-100'}`}>
                {refreshStatus==='loading'?<><Spinner/>Checking…</>:refreshStatus==='done'?'✓ Up to date':refreshStatus==='error'?'⚠ Retry':<><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"/></svg>Refresh live data</>}
              </button>
              <button onClick={handlePushToClickUp} disabled={pushStatus==='loading'} className={`flex items-center gap-2 px-3 py-2 rounded-lg text-sm font-medium border transition-colors ${pushStatus==='loading'?'bg-gray-100 text-gray-400 border-gray-200 cursor-not-allowed':pushStatus==='done'?'bg-green-50 text-green-700 border-green-200 hover:bg-green-100':pushStatus==='error'?'bg-red-50 text-red-700 border-red-200':'bg-purple-50 text-purple-700 border-purple-200 hover:bg-purple-100'}`}>
                {pushStatus==='loading'?<><Spinner/>Pushing…</>:pushStatus==='done'?'✓ Pushed':pushStatus==='error'?'⚠ Failed':<><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"/></svg>Push to ClickUp</>}
              </button>
            </div>
          </div>
          <div className="flex gap-1 mt-4 ml-11">
            {["BPN","TRAILS"].map(p => (
              <button key={p} onClick={()=>switchProduct(p)} className={`px-5 py-2 rounded-t-lg text-sm font-semibold border-b-2 transition-colors ${product===p?p==="BPN"?"border-blue-600 text-blue-700 bg-blue-50":"border-emerald-600 text-emerald-700 bg-emerald-50":"border-transparent text-gray-500 hover:text-gray-700 hover:bg-gray-100"}`}>
                {p==="BPN"?"🏦 BPN (Regulated)":"🔌 Trails (API)"}
              </button>
            ))}
            <div className={`ml-3 self-center text-xs px-2 py-1 rounded-full font-medium ${product==="BPN"?"bg-blue-100 text-blue-700":"bg-emerald-100 text-emerald-700"}`}>
              {product==="BPN"?"Corporate Onboarding · MSB · Regulated":"Passive · Non-Custodial · API"}
            </div>
          </div>
          {refreshLog.length > 0 && (
            <div className="mt-2 ml-11 space-y-1">
              {refreshLog.map((l,i) => (
                <div key={i} className={`text-xs px-3 py-1.5 rounded-lg border ${l.type==='warn'?'bg-amber-50 text-amber-800 border-amber-200':l.type==='ok'?'bg-green-50 text-green-800 border-green-200':l.type==='error'?'bg-red-50 text-red-800 border-red-200':'bg-blue-50 text-blue-800 border-blue-200'}`}>
                  {l.type==='warn'?'⚠ ':l.type==='ok'?'✓ ':l.type==='error'?'✕ ':'ℹ '}{l.msg}
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      <div className="max-w-6xl mx-auto px-6 py-6">
        <div className={`grid gap-2 mb-6 ${stats.discretionary>0?'grid-cols-4 md:grid-cols-8':'grid-cols-4 md:grid-cols-7'}`}>
          {[
            {label:"Total",val:stats.total,color:"border-gray-300 bg-white",tc:"text-gray-800"},
            {label:"Allowed",val:stats.allowed,color:"border-green-300 bg-green-50",tc:"text-green-700"},
            {label:"Prohibited",val:stats.prohibited,color:"border-red-300 bg-red-50",tc:"text-red-700"},
            {label:"High Risk (EDD)",val:stats.edd,color:"border-yellow-300 bg-yellow-50",tc:"text-yellow-700"},
            ...(stats.discretionary>0?[{label:"Discretionary",val:stats.discretionary,color:"border-orange-300 bg-orange-50",tc:"text-orange-700"}]:[]),
            {label:"FATF Black",val:stats.fatfBlack,color:"border-gray-300 bg-gray-50",tc:"text-gray-700"},
            {label:"FATF Grey",val:stats.fatfGrey,color:"border-gray-300 bg-gray-50",tc:"text-gray-700"},
            {label:"Crypto Ban",val:stats.crypto,color:"border-gray-300 bg-gray-50",tc:"text-gray-700"},
          ].map(s => (
            <div key={s.label} className={`border rounded-lg p-2.5 ${s.color}`}>
              <div className={`text-xl font-bold ${s.tc}`}>{s.val}</div>
              <div className="text-xs text-gray-500 mt-0.5 leading-tight">{s.label}</div>
            </div>
          ))}
        </div>

        <div className="bg-white border border-gray-200 rounded-lg p-4 mb-4 flex flex-wrap gap-3 items-center">
          <input className="border border-gray-300 rounded px-3 py-2 text-sm flex-1 min-w-40 focus:outline-none focus:ring-1 focus:ring-gray-400" placeholder="Search country or region..." value={search} onChange={e=>{setSearch(e.target.value);setExpanded(null);}}/>
          <select className="border border-gray-300 rounded px-3 py-2 text-sm bg-white" value={filterStatus} onChange={e=>{setFilterStatus(e.target.value);setExpanded(null);}}>
            <option value="ALL">All Statuses</option>
            <option value={A}>Allowed</option>
            <option value={P}>Prohibited</option>
            <option value={E}>High Risk (EDD)</option>
            {stats.discretionary>0&&<option value={D}>Discretionary</option>}
          </select>
          <select className="border border-gray-300 rounded px-3 py-2 text-sm bg-white" value={filterRegion} onChange={e=>{setFilterRegion(e.target.value);setExpanded(null);}}>
            {regions.map(r=><option key={r} value={r}>{r==="ALL"?"All Regions":r}</option>)}
          </select>
          <select className="border border-gray-300 rounded px-3 py-2 text-sm bg-white" value={filterFlag} onChange={e=>{setFilterFlag(e.target.value);setExpanded(null);}}>
            <option value="ALL">All Flags</option>
            <option value="FATF_BLACK">FATF Blacklist</option>
            <option value="FATF_GREY">FATF Greylist</option>
            <option value="CRYPTO_BAN">Crypto Ban</option>
            <option value="COMP">Comprehensive Sanctions</option>
            <option value="SANCTIONS">Any Sanctions</option>
          </select>
          <select className="border border-gray-300 rounded px-3 py-2 text-sm bg-white" value={sortBy} onChange={e=>setSortBy(e.target.value)}>
            <option value="name">Sort: A-Z</option>
            <option value="status">Sort: Status</option>
            <option value="region">Sort: Region</option>
          </select>
          <span className="text-sm text-gray-500 ml-auto font-medium">{filtered.length} / {stats.total}</span>
        </div>

        <div className="flex flex-wrap gap-2 mb-4 text-xs">
          {[{label:"FATF Black",color:"bg-red-700 text-white"},{label:"FATF Grey",color:"bg-orange-400 text-white"},{label:"Crypto Ban",color:"bg-violet-600 text-white"},{label:"Comp. Sanctions",color:"bg-rose-600 text-white"},{label:"OFAC",color:"bg-blue-100 text-blue-800"},{label:"EU",color:"bg-purple-100 text-purple-800"},{label:"UN",color:"bg-gray-200 text-gray-800"},{label:"UK",color:"bg-green-100 text-green-800"},{label:"Canada",color:"bg-red-100 text-red-800"}].map(l=>(
            <span key={l.label} className={`px-2 py-1 rounded-full font-medium ${l.color}`}>{l.label}</span>
          ))}
        </div>

        <div className="bg-white border border-gray-200 rounded-lg overflow-hidden">
          <div className="grid grid-cols-12 bg-gray-50 border-b border-gray-200 px-4 py-2.5 text-xs font-semibold text-gray-500 uppercase tracking-wide">
            <div className="col-span-3">Country</div>
            <div className="col-span-1 text-center">Region</div>
            <div className="col-span-3 text-center">Flags</div>
            <div className="col-span-2 text-center">Sanctioning Bodies</div>
            <div className="col-span-2 text-center">Status</div>
            <div className="col-span-1"></div>
          </div>
          {filtered.length===0&&<div className="text-center py-12 text-gray-400 text-sm">No countries match your filters.</div>}
          {filtered.map((c,i) => {
            const cfg = STATUS_CONFIG[c.status]||STATUS_CONFIG[A];
            const isOpen = expanded===i;
            return (
              <div key={c.name+i} className={`border-b border-gray-100 last:border-0 ${isOpen?cfg.bg:cfg.row} transition-colors`}>
                <div className="grid grid-cols-12 px-4 py-2.5 items-center gap-1 cursor-pointer" onClick={()=>setExpanded(isOpen?null:i)}>
                  <div className="col-span-3 font-medium text-gray-900 text-sm">{c.name}</div>
                  <div className="col-span-1 text-center text-xs text-gray-500">{c.region}</div>
                  <div className="col-span-3 flex flex-wrap gap-1 justify-center">
                    {c.fatfBlack&&<span className="px-1.5 py-0.5 rounded text-xs font-semibold bg-red-700 text-white">FATF Black</span>}
                    {c.fatfGrey&&<span className="px-1.5 py-0.5 rounded text-xs font-semibold bg-orange-400 text-white">FATF Grey</span>}
                    {c.cryptoBan&&<span className="px-1.5 py-0.5 rounded text-xs font-semibold bg-violet-600 text-white">Crypto Ban</span>}
                    {c.comp&&<span className="px-1.5 py-0.5 rounded text-xs font-semibold bg-rose-600 text-white">Comp. Sanctions</span>}
                    {!c.fatfBlack&&!c.fatfGrey&&!c.cryptoBan&&!c.comp&&c.bodies.length===0&&<span className="text-xs text-gray-300">None</span>}
                  </div>
                  <div className="col-span-2 flex flex-wrap gap-1 justify-center">
                    {c.bodies.map(b=><span key={b} className={`px-1.5 py-0.5 rounded text-xs font-medium ${BODY_COLORS[b]}`}>{b}</span>)}
                    {c.bodies.length===0&&<span className="text-xs text-gray-300">None</span>}
                  </div>
                  <div className="col-span-2 flex justify-center">
                    <span className={`px-2 py-1 rounded-full text-xs font-bold whitespace-nowrap ${cfg.badge}`}>{c.status}</span>
                  </div>
                  <div className="col-span-1 flex justify-end">
                    <svg className={`w-4 h-4 text-gray-300 transition-transform ${isOpen?"rotate-180":""}`} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7"/></svg>
                  </div>
                </div>
                {isOpen&&(
                  <div className={`px-4 pb-4 pt-1 ${cfg.bg}`}>
                    <div className={`text-sm text-gray-700 bg-white border ${cfg.border} rounded-lg p-4 leading-relaxed whitespace-pre-line`}>
                      {c.notes}
                    </div>
                  </div>
                )}
              </div>
            );
          })}
        </div>
        <p className="text-xs text-gray-400 mt-4 text-center">{lastUpdated} · {product} product view · Sources: FATF, OFAC, EU Sanctions Map, UK OFSI, UN Security Council, Global Affairs Canada · Reference only — verify against official sources.</p>
      </div>
    </div>
  );
}
